import React, { useState } from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import LineChart from '../../components/charts/LineChart';
import BarChart from '../../components/charts/BarChart';
import PieChart from '../../components/charts/PieChart';

const MyProgress = () => {
  const userName = localStorage.getItem('userName') || 'Student';
  const [period, setPeriod] = useState('7days');

  const accuracyData = {
    labels: period === '7days' 
      ? ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
      : ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
    datasets: [{
      label: 'Accuracy %',
      data: period === '7days' ? [65, 70, 68, 75, 72, 78, 80] : [68, 72, 75, 78],
      borderColor: 'rgb(59, 130, 246)',
      backgroundColor: 'rgba(59, 130, 246, 0.5)',
    }],
  };

  const topicScores = {
    labels: ['Arrays', 'Strings', 'Trees', 'DBMS', 'OS'],
    datasets: [{
      label: 'Score %',
      data: [85, 70, 65, 80, 75],
      backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'],
    }],
  };

  const correctIncorrect = {
    labels: ['Correct', 'Incorrect'],
    datasets: [{
      data: [156, 44],
      backgroundColor: ['#10b981', '#ef4444'],
    }],
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-3xl font-bold text-gray-800">My Progress</h2>
            <select
              value={period}
              onChange={(e) => setPeriod(e.target.value)}
              className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="7days">Last 7 Days</option>
              <option value="30days">Last 30 Days</option>
            </select>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
            <div className="bg-white rounded-lg shadow p-6">
              <LineChart data={accuracyData} title="Accuracy Over Time" />
            </div>
            <div className="bg-white rounded-lg shadow p-6">
              <BarChart data={topicScores} title="Topic-wise Scores" />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white rounded-lg shadow p-6">
              <PieChart data={correctIncorrect} title="Correct vs Incorrect" />
            </div>
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-semibold mb-4">Summary Statistics</h3>
              <div className="space-y-4">
                <div className="flex justify-between border-b pb-2">
                  <span className="text-gray-600">Total Questions Attempted</span>
                  <span className="font-semibold">200</span>
                </div>
                <div className="flex justify-between border-b pb-2">
                  <span className="text-gray-600">Correct Answers</span>
                  <span className="font-semibold text-green-600">156</span>
                </div>
                <div className="flex justify-between border-b pb-2">
                  <span className="text-gray-600">Incorrect Answers</span>
                  <span className="font-semibold text-red-600">44</span>
                </div>
                <div className="flex justify-between border-b pb-2">
                  <span className="text-gray-600">Overall Accuracy</span>
                  <span className="font-semibold text-blue-600">78%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Average Time per Question</span>
                  <span className="font-semibold">6.2 min</span>
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default MyProgress;
